# Pester tests for CsvReportGenerator module
# TDD approach: each Describe block was written as a failing test first,
# then the implementation was added to make it pass.

Set-StrictMode -Latest
$ErrorActionPreference = 'Stop'

# Import the module under test
$ModulePath = Join-Path -Path $PSScriptRoot -ChildPath '..\src\CsvReportGenerator.psm1'
if (Test-Path -Path $ModulePath) {
    Import-Module -Name $ModulePath -Force
}

# Path to test fixtures
$FixturePath = Join-Path -Path $PSScriptRoot -ChildPath 'fixtures\employees.csv'

# ============================================================================
# RED/GREEN CYCLE 1: Import CSV and filter active employees
# ============================================================================
Describe 'Import-EmployeeCsv' {
    Context 'when given a valid CSV file' {
        It 'should import all rows from the CSV' {
            [System.Collections.ArrayList]$result = Import-EmployeeCsv -Path $FixturePath
            # The fixture has 12 employee rows
            $result.Count | Should -Be 12
        }

        It 'should return objects with expected properties' {
            [System.Collections.ArrayList]$result = Import-EmployeeCsv -Path $FixturePath
            $first = $result[0]
            $first.name | Should -Be 'Alice Johnson'
            $first.department | Should -Be 'Engineering'
            $first.salary | Should -Be '95000'
            $first.hire_date | Should -Be '2020-01-15'
            $first.status | Should -Be 'active'
        }
    }

    Context 'when given a non-existent file' {
        It 'should throw a meaningful error' {
            { Import-EmployeeCsv -Path 'nonexistent.csv' } |
                Should -Throw '*does not exist*'
        }
    }

    Context 'when given an empty file path' {
        It 'should throw a parameter validation error' {
            { Import-EmployeeCsv -Path '' } |
                Should -Throw
        }
    }
}

Describe 'Get-ActiveEmployees' {
    BeforeAll {
        # Create mock employee data matching CSV structure
        [PSCustomObject[]]$script:AllEmployees = @(
            [PSCustomObject]@{ name = 'Alice'; department = 'Eng'; salary = '90000'; hire_date = '2020-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Bob'; department = 'Eng'; salary = '80000'; hire_date = '2019-01-01'; status = 'inactive' }
            [PSCustomObject]@{ name = 'Carol'; department = 'Sales'; salary = '70000'; hire_date = '2021-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Dave'; department = 'Sales'; salary = '75000'; hire_date = '2022-01-01'; status = 'Active' }
        )
    }

    It 'should return only employees with active status' {
        [PSCustomObject[]]$result = Get-ActiveEmployees -Employees $script:AllEmployees
        $result.Count | Should -Be 3
    }

    It 'should handle case-insensitive status matching' {
        [PSCustomObject[]]$result = Get-ActiveEmployees -Employees $script:AllEmployees
        [string[]]$names = $result | ForEach-Object { $_.name }
        $names | Should -Contain 'Dave'
    }

    It 'should return empty array when no active employees exist' {
        [PSCustomObject[]]$inactive = @(
            [PSCustomObject]@{ name = 'X'; department = 'D'; salary = '1'; hire_date = '2020-01-01'; status = 'inactive' }
        )
        [PSCustomObject[]]$result = Get-ActiveEmployees -Employees $inactive
        $result.Count | Should -Be 0
    }
}

# ============================================================================
# RED/GREEN CYCLE 2: Department aggregates (avg salary, headcount)
# ============================================================================
Describe 'Get-DepartmentAggregates' {
    BeforeAll {
        [PSCustomObject[]]$script:ActiveEmployees = @(
            [PSCustomObject]@{ name = 'Alice'; department = 'Engineering'; salary = '100000'; hire_date = '2020-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Bob'; department = 'Engineering'; salary = '80000'; hire_date = '2019-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Carol'; department = 'Marketing'; salary = '70000'; hire_date = '2021-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Dave'; department = 'Marketing'; salary = '60000'; hire_date = '2022-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Eve'; department = 'Marketing'; salary = '75000'; hire_date = '2020-06-01'; status = 'active' }
        )
    }

    It 'should return one entry per department' {
        [hashtable]$result = Get-DepartmentAggregates -Employees $script:ActiveEmployees
        $result.Keys.Count | Should -Be 2
    }

    It 'should compute correct headcount per department' {
        [hashtable]$result = Get-DepartmentAggregates -Employees $script:ActiveEmployees
        [int]$engCount = $result['Engineering'].Headcount
        [int]$mktCount = $result['Marketing'].Headcount
        $engCount | Should -Be 2
        $mktCount | Should -Be 3
    }

    It 'should compute correct average salary per department' {
        [hashtable]$result = Get-DepartmentAggregates -Employees $script:ActiveEmployees
        [decimal]$engAvg = $result['Engineering'].AverageSalary
        [decimal]$mktAvg = $result['Marketing'].AverageSalary
        # Engineering: (100000 + 80000) / 2 = 90000
        $engAvg | Should -Be 90000
        # Marketing: (70000 + 60000 + 75000) / 3 = 68333.33
        [decimal]$expectedMkt = [math]::Round(68333.33, 2)
        $mktAvg | Should -Be $expectedMkt
    }

    It 'should compute correct total salary per department' {
        [hashtable]$result = Get-DepartmentAggregates -Employees $script:ActiveEmployees
        [decimal]$engTotal = $result['Engineering'].TotalSalary
        $engTotal | Should -Be 180000
    }

    It 'should handle empty employee list' {
        [PSCustomObject[]]$empty = @()
        [hashtable]$result = Get-DepartmentAggregates -Employees $empty
        $result.Keys.Count | Should -Be 0
    }
}

# ============================================================================
# RED/GREEN CYCLE 3: Overall statistics
# ============================================================================
Describe 'Get-OverallStatistics' {
    BeforeAll {
        [PSCustomObject[]]$script:ActiveEmployees = @(
            [PSCustomObject]@{ name = 'Alice'; department = 'Eng'; salary = '100000'; hire_date = '2020-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Bob'; department = 'Eng'; salary = '80000'; hire_date = '2019-01-01'; status = 'active' }
            [PSCustomObject]@{ name = 'Carol'; department = 'Sales'; salary = '60000'; hire_date = '2021-01-01'; status = 'active' }
        )
    }

    It 'should return correct total headcount' {
        [hashtable]$stats = Get-OverallStatistics -Employees $script:ActiveEmployees
        $stats.TotalHeadcount | Should -Be 3
    }

    It 'should return correct overall average salary' {
        [hashtable]$stats = Get-OverallStatistics -Employees $script:ActiveEmployees
        # (100000 + 80000 + 60000) / 3 = 80000
        $stats.AverageSalary | Should -Be 80000
    }

    It 'should return correct min and max salary' {
        [hashtable]$stats = Get-OverallStatistics -Employees $script:ActiveEmployees
        $stats.MinSalary | Should -Be 60000
        $stats.MaxSalary | Should -Be 100000
    }

    It 'should return correct total salary' {
        [hashtable]$stats = Get-OverallStatistics -Employees $script:ActiveEmployees
        $stats.TotalSalary | Should -Be 240000
    }

    It 'should return correct department count' {
        [hashtable]$stats = Get-OverallStatistics -Employees $script:ActiveEmployees
        $stats.DepartmentCount | Should -Be 2
    }

    It 'should handle empty employee list gracefully' {
        [PSCustomObject[]]$empty = @()
        [hashtable]$stats = Get-OverallStatistics -Employees $empty
        $stats.TotalHeadcount | Should -Be 0
        $stats.AverageSalary | Should -Be 0
        $stats.MinSalary | Should -Be 0
        $stats.MaxSalary | Should -Be 0
    }
}

# ============================================================================
# RED/GREEN CYCLE 4: Report formatting and file output
# ============================================================================
Describe 'Format-SummaryReport' {
    BeforeAll {
        [hashtable]$script:DeptAggregates = @{
            'Engineering' = @{ Headcount = 2; AverageSalary = [decimal]90000.00; TotalSalary = [decimal]180000 }
            'Marketing'   = @{ Headcount = 3; AverageSalary = [decimal]68333.33; TotalSalary = [decimal]205000 }
        }
        [hashtable]$script:OverallStats = @{
            TotalHeadcount  = 5
            AverageSalary   = [decimal]77000.00
            MinSalary       = [decimal]60000
            MaxSalary       = [decimal]100000
            TotalSalary     = [decimal]385000
            DepartmentCount = 2
        }
    }

    It 'should return a non-empty string' {
        [string]$report = Format-SummaryReport -DepartmentAggregates $script:DeptAggregates -OverallStatistics $script:OverallStats
        $report | Should -Not -BeNullOrEmpty
    }

    It 'should include a header section' {
        [string]$report = Format-SummaryReport -DepartmentAggregates $script:DeptAggregates -OverallStatistics $script:OverallStats
        $report | Should -Match 'Employee Summary Report'
    }

    It 'should include department names' {
        [string]$report = Format-SummaryReport -DepartmentAggregates $script:DeptAggregates -OverallStatistics $script:OverallStats
        $report | Should -Match 'Engineering'
        $report | Should -Match 'Marketing'
    }

    It 'should include overall statistics' {
        [string]$report = Format-SummaryReport -DepartmentAggregates $script:DeptAggregates -OverallStatistics $script:OverallStats
        $report | Should -Match 'Overall Statistics'
        $report | Should -Match '5'
    }

    It 'should include salary figures formatted with dollar signs' {
        [string]$report = Format-SummaryReport -DepartmentAggregates $script:DeptAggregates -OverallStatistics $script:OverallStats
        $report | Should -Match '\$'
    }
}

Describe 'Export-Report' {
    BeforeAll {
        $script:TestOutputDir = Join-Path -Path $PSScriptRoot -ChildPath 'test_output'
        if (-not (Test-Path -Path $script:TestOutputDir)) {
            New-Item -Path $script:TestOutputDir -ItemType Directory | Out-Null
        }
    }

    AfterAll {
        # Clean up test output
        if (Test-Path -Path $script:TestOutputDir) {
            Remove-Item -Path $script:TestOutputDir -Recurse -Force
        }
    }

    It 'should write report content to the specified file' {
        [string]$outputPath = Join-Path -Path $script:TestOutputDir -ChildPath 'test_report.txt'
        [string]$content = 'Test report content'
        Export-Report -Content $content -OutputPath $outputPath
        Test-Path -Path $outputPath | Should -BeTrue
        [string]$written = Get-Content -Path $outputPath -Raw
        $written | Should -Match 'Test report content'
    }

    It 'should throw when given an invalid directory' {
        { Export-Report -Content 'test' -OutputPath '/nonexistent_dir_xyz/report.txt' } |
            Should -Throw
    }
}

# ============================================================================
# RED/GREEN CYCLE 5: End-to-end integration test
# ============================================================================
Describe 'New-EmployeeReport (Integration)' {
    BeforeAll {
        $script:TestOutputDir = Join-Path -Path $PSScriptRoot -ChildPath 'test_output_integration'
        if (-not (Test-Path -Path $script:TestOutputDir)) {
            New-Item -Path $script:TestOutputDir -ItemType Directory | Out-Null
        }
        $script:OutputFile = Join-Path -Path $script:TestOutputDir -ChildPath 'integration_report.txt'
    }

    AfterAll {
        if (Test-Path -Path $script:TestOutputDir) {
            Remove-Item -Path $script:TestOutputDir -Recurse -Force
        }
    }

    It 'should generate a complete report from the CSV fixture' {
        New-EmployeeReport -CsvPath $FixturePath -OutputPath $script:OutputFile
        Test-Path -Path $script:OutputFile | Should -BeTrue
    }

    It 'should contain expected departments in the report' {
        [string]$report = Get-Content -Path $script:OutputFile -Raw
